const { Pact, Matchers } = require('@pact-foundation/pact');

const provider = new Pact({ consumer: 'Frontend', provider: 'UserAPI', port: 8080 });

describe('User API contract', () => {
  beforeAll(() => provider.setup());
  afterAll(() => provider.finalize());

  it('gets a user by ID', async () => {
    await provider.addInteraction({
      state: 'user 123 exists',
      uponReceiving: 'GET /users/123 with auth',
      withRequest: { method: 'GET', path: '/users/123',
        headers: { Authorization: 'Bearer token' } },
      willRespondWith: {
        status: 200,
        body: { id: '123', name: Matchers.string('John'), email: Matchers.email() }
      }
    });
    const response = await userClient.getUser('123');
    expect(response.id).toBe('123');
  });
});

import pytest
from fastapi.testclient import TestClient
from app import app

@pytest.fixture
def client():
    return TestClient(app)

@pytest.fixture
def auth_headers(client):
    token = client.post("/auth/login",
        json={"email": "test@example.com", "password": "password"}
    ).json()["access_token"]
    return {"Authorization": f"Bearer {token}"}

class TestUsers:
    def test_create_user_201(self, client, auth_headers):
        r = client.post("/users",
            json={"name": "New User", "email": "new@example.com"},
            headers=auth_headers)
        assert r.status_code == 201
        assert r.json()["name"] == "New User"

    def test_get_user_404(self, client, auth_headers):
        r = client.get("/users/nonexistent", headers=auth_headers)
        assert r.status_code == 404
        assert r.json()["type"].endswith("/not-found")

    def test_create_user_422_invalid_email(self, client, auth_headers):
        r = client.post("/users",
            json={"name": "", "email": "invalid"},
            headers=auth_headers)
        assert r.status_code == 400
        errors = r.json()["errors"]
        assert any(e["field"] == "email" for e in errors)

    def test_create_user_401_no_auth(self, client):
        r = client.post("/users", json={"name": "X", "email": "x@x.com"})
        assert r.status_code == 401
